import{_ as e,o as r,c as a,Q as i}from"./chunks/framework.32dba02b.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Linux/index.md","filePath":"Linux/index.md","lastUpdated":1695439204000}'),t={name:"Linux/index.md"},n=i('<h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><blockquote><p><strong>Linux</strong>是一种<a href="https://zh.wikipedia.org/wiki/%E8%87%AA%E7%94%B1%E5%8F%8A%E5%BC%80%E6%94%BE%E6%BA%90%E4%BB%A3%E7%A0%81%E8%BD%AF%E4%BB%B6" target="_blank" rel="noreferrer">自由和开放源码</a>的<a href="https://zh.wikipedia.org/wiki/%E7%B1%BBUnix%E7%B3%BB%E7%BB%9F" target="_blank" rel="noreferrer">类UNIX</a><a href="https://zh.wikipedia.org/wiki/%E4%BD%9C%E6%A5%AD%E7%B3%BB%E7%B5%B1" target="_blank" rel="noreferrer">操作系统</a>。该操作系统的<a href="https://zh.wikipedia.org/wiki/%E5%86%85%E6%A0%B8" target="_blank" rel="noreferrer">内核</a>由<a href="https://zh.wikipedia.org/wiki/%E6%9E%97%E7%BA%B3%E6%96%AF%C2%B7%E6%89%98%E7%93%A6%E5%85%B9" target="_blank" rel="noreferrer">林纳斯·托瓦兹</a>在1991年10月5日首次发布[<a href="https://zh.wikipedia.org/zh-cn/Linux#cite_note-6" target="_blank" rel="noreferrer">6]</a>[<a href="https://zh.wikipedia.org/zh-cn/Linux#cite_note-7" target="_blank" rel="noreferrer">7]</a>，再加上<a href="https://zh.wikipedia.org/wiki/%E4%BD%BF%E7%94%A8%E8%80%85%E7%A9%BA%E9%96%93" target="_blank" rel="noreferrer">用户空间</a>的<a href="https://zh.wikipedia.org/wiki/%E6%87%89%E7%94%A8%E7%A8%8B%E5%BC%8F" target="_blank" rel="noreferrer">应用程序</a>之后，就成为了Linux操作系统。Linux也是<a href="https://zh.wikipedia.org/wiki/%E8%87%AA%E7%94%B1%E8%BD%AF%E4%BB%B6" target="_blank" rel="noreferrer">自由软件</a>和<a href="https://zh.wikipedia.org/wiki/%E5%BC%80%E6%94%BE%E6%BA%90%E4%BB%A3%E7%A0%81%E8%BD%AF%E4%BB%B6" target="_blank" rel="noreferrer">开放源代码软件</a>发展中最著名的例子。只要遵循<a href="https://zh.wikipedia.org/wiki/GNU%E9%80%9A%E7%94%A8%E5%85%AC%E5%85%B1%E8%AE%B8%E5%8F%AF%E8%AF%81" target="_blank" rel="noreferrer">GNU 通用公共许可证</a>（GPL），任何个人和机构都可以自由地使用Linux的所有底层<a href="https://zh.wikipedia.org/wiki/%E6%BA%90%E4%BB%A3%E7%A0%81" target="_blank" rel="noreferrer">源代码</a>，也可以自由地修改和再发布。大多数Linux系统还包括像提供<a href="https://zh.wikipedia.org/wiki/GUI" target="_blank" rel="noreferrer">GUI</a>的<a href="https://zh.wikipedia.org/wiki/X_Window" target="_blank" rel="noreferrer">X Window</a>之类的程序。除了一部分专家之外，大多数人都是直接使用<a href="https://zh.wikipedia.org/wiki/Linux%E7%99%BC%E8%A1%8C%E7%89%88" target="_blank" rel="noreferrer">Linux 发行版</a>，而不是自己选择每一样组件或自行设置。</p></blockquote>',2),o=[n];function E(h,B,k,l,p,_){return r(),a("div",null,o)}const d=e(t,[["render",E]]);export{f as __pageData,d as default};
